    int celebrity = -1;
    for(int i = 0; i < n; i++) {
        if (celebrity == -1)
            celebrity = i;
        else {
            if (matrix[celebrity][i] == "true")
                celebrity = i;
        }
    }
    for(int i = 0; i < n; i++) {
        if(i != celebrity) {
            if (matrix[celebrity][i] != "false" || matrix[i][celebrity] == "false") {
                cout << -1 << endl;
                return 0;
            }
        }
    }
    cout << celebrity << endl;
